+        Self {
+            tmp,
+            db_path,
+            storage_root,
+        }
+    }
+
+    fn database_url(&self) -> String {
+        format!("sqlite:///{}", self.db_path.display())
+    }
+
+    fn base_env(&self) -> Vec<(String, String)> {
