+fn run_am(env: &[(String, String)], args: &[&str]) -> Output {
+    let mut cmd = Command::new(am_bin());
+    cmd.args(args)
+        .stdin(Stdio::null())
+        .stdout(Stdio::piped())
+        .stderr(Stdio::piped());
+    for (k, v) in env {
+        cmd.env(k, v);
+    }
+    cmd.output().expect("spawn am")
+}
